from anthropic import Anthropic
import json

client = Anthropic()

tools = [
    {
        "name": "extract_entity",
        "description": "Extract a named entity from text",
        "input_schema": {
            "type": "object",
            "properties": {
                "entity": {"type": "string"},
                "entity_type": {"type": "string", "enum": ["person", "org", "location"]},
                "confidence": {"type": "number", "minimum": 0, "maximum": 1},
            },
            "required": ["entity", "entity_type", "confidence"],
        },
    }
]

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=256,
    tools=tools,
    tool_choice={"type": "tool", "name": "extract_entity"},
    messages=[{"role": "user", "content": "Anthropic was founded in San Francisco."}],
)

tool_use = next(b for b in response.content if b.type == "tool_use")
entity: dict = tool_use.input  # always matches schema — no parsing needed
print(json.dumps(entity, indent=2))
# {"entity": "Anthropic", "entity_type": "org", "confidence": 0.99}

from dataclasses import dataclass

@dataclass
class RadarScore:
    name: str
    production_evidence: int    # 0-3: 0=none, 1=external, 2=internal pilot, 3=internal prod
    api_stability: int          # 0-3: 0=experimental, 1=minor-break, 2=semver minor, 3=LTS
    security_compliance: int    # 0-3: 0=none, 1=SOC2, 2=SOC2+audit, 3=SOC2+HIPAA/FedRAMP
    community_support: int      # 0-3: 0=solo, 1=small, 2=mid-size, 3=large ecosystem
    vendor_risk: int            # 0-3: 0=no vendor, 1=startup, 2=VC-backed, 3=public/acquired
    performance_fit: int        # 0-3: 0=unproven, 1=benchmarked, 2=meets SLA, 3=headroom

    @property
    def total(self) -> int:
        return (self.production_evidence + self.api_stability +
                self.security_compliance + self.community_support +
                self.vendor_risk + self.performance_fit)

    @property
    def ring(self) -> str:
        if self.total >= 14:
            return "Adopt"
        elif self.total >= 9:
            return "Trial"
        elif self.total >= 5:
            return "Assess"
        else:
            return "Hold"


scores = [
    RadarScore("Azure OpenAI",       3, 3, 3, 3, 3, 3),  # 18 → Adopt
    RadarScore("LangChain 0.2",      2, 2, 1, 3, 2, 2),  # 12 → Trial
    RadarScore("AutoGen",            1, 1, 1, 2, 2, 2),  # 9  → Trial
    RadarScore("DSPy",               1, 1, 1, 1, 2, 1),  # 7  → Assess
    RadarScore("FAISS standalone",   2, 2, 1, 2, 3, 1),  # 11 → Trial  ← re-assess annually
    RadarScore("GPT-3.5-turbo",      3, 2, 2, 3, 3, 1),  # 14 → Adopt  ← but Hold for new projects
]

for s in scores:
    print(f"{s.name:25s}  score={s.total:2d}  ring={s.ring}")
